const root=document.getElementById('app');
const state={token:localStorage.getItem('token')||'',me:null,system:null,secrets:null,permCatalog:null,stylePreview:null,stylePreviewFor:'',stylePreviewSource:'',page:'projects',projects:[],styles:[],users:[],usage:{},models:{text_models:[],image_models:[]},assets:[],selected:null,events:[],artifact:null,tab:'overview',search:'',status:'all',sort:'created_at_desc',category:'all',projectView:localStorage.getItem('projectView')||'cards',styleEdit:null,styleTab:'general',generatedStyle:null,styleIssues:[],styleVersions:[],mediaFilter:'all',mediaRole:'all',mediaProject:'all',mediaSort:'created_desc',mediaSearch:''};
const STATUS={draft:'Чернетка',queued:'У черзі',processing:'Генерація',review:'На перевірці',changes_requested:'Потрібні зміни',approved:'Схвалено',done:'Готово',error:'Помилка',paused:'Пауза',cancelled:'Скасовано'};
const STAGE={queued:'Очікування запуску',scrape:'Читання сторінки',extract:'Аналіз товару',images:'Підготовка зображень',content:'Створення rich-контенту',review:'Готово до перевірки',approved:'Схвалено',changes_requested:'Потрібні зміни',error:'Помилка',paused:'Призупинено',cancelled:'Скасовано'};
const ROLE_LABEL={admin:'Адміністратор',editor:'Редактор',reviewer:'Рев’юер',viewer:'Перегляд'};
const CRITIC_LABEL={html:'HTML-структура',facts:'Фактологія',accessibility:'Доступність',marketing:'Маркетинг'};
const MANAGED_STYLE_NAMES=['ARTLINE Base','ARTLINE Engineering'];
const LANG={ru:'Російська',ua:'Українська',uk:'Українська (uk)',pl:'Польська',en:'Англійська',de:'Німецька',fr:'Французька',es:'Іспанська',it:'Італійська',cs:'Чеська',sk:'Словацька',ro:'Румунська',hu:'Угорська',nl:'Нідерландська',pt:'Португальська',bg:'Болгарська',lt:'Литовська',lv:'Латвійська',et:'Естонська'}, VARIANT={desktop:'Десктоп',mobile:'Мобільна'};
const LANGUAGE_OPTIONS=['ru','ua','pl','en','de','fr','es','it','cs','sk','ro','hu','nl','pt'];
const ASSET_LABEL={
  'product-reference':'Фото товару · референс','hero-generated':'Hero · AI','hero-desktop-generated':'Hero Desktop · AI','hero-mobile-generated':'Hero Mobile · AI','feature-generated':'Feature · AI',
  'hero-source':'Hero · оригінал','feature-source':'Feature · оригінал','hero-custom':'Hero · власне','feature-custom':'Feature · власне'
};
const assetLabel=a=>ASSET_LABEL[a?.label]||a?.label||'Зображення';
const assetCategory=a=>(a?.label||'').includes('generated')?'generated':(a?.label||'').includes('custom')?'custom':(a?.label||'').includes('reference')||a?.model==='source'?'source':'other';
const assetRole=a=>{const label=(a?.label||'').toLowerCase();return label.includes('hero')?'hero':label.includes('feature')?'feature':label.includes('reference')?'reference':'other'};
const languageLabel=code=>LANG[code]||String(code||'').toUpperCase();
const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const LOGO='https://artline.ua/client/images/icons/svg/logo-main-header.svg';
let pendingSave=false;
let styleSaveTimer=null,styleSaveRevision=0,styleSaveBusy=false,stylePendingSave=null;
// API timestamps are naive UTC; append Z so they render in the viewer's timezone.
const utc=v=>new Date(String(v).endsWith('Z')?v:v+'Z');
const money=n=>`$${Number(n||0).toFixed(4)}`, dt=v=>v?utc(v).toLocaleString('uk-UA'):'—';
const rel=v=>{if(!v)return '—';const s=(Date.now()-utc(v).getTime())/1000;if(s<60)return 'щойно';if(s<3600)return `${Math.floor(s/60)} хв тому`;if(s<86400)return `${Math.floor(s/3600)} год тому`;if(s<172800)return 'вчора';return utc(v).toLocaleDateString('uk-UA')}
async function api(path,opt={}){const h={'Content-Type':'application/json',...(opt.headers||{})};if(state.token)h.Authorization=`Bearer ${state.token}`;const r=await fetch(path,{...opt,headers:h});const t=await r.text();let d=t;try{d=t?JSON.parse(t):null}catch{}if(r.status===401&&path!='/api/auth/login'){localStorage.removeItem('token');state.token='';render();throw Error('Сесію завершено')}if(!r.ok)throw Error(d?.detail||d||`HTTP ${r.status}`);return d}
function toastStack(){let s=document.getElementById('toastStack');if(!s){s=document.createElement('div');s.id='toastStack';document.body.append(s)}return s}
function toast(text,bad=false){const n=document.createElement('div');n.className=`toast ${bad?'bad':''}`;n.textContent=text;toastStack().append(n);setTimeout(()=>n.remove(),3400)}
function setOffline(on){let b=document.getElementById('offlineBanner');if(on&&!b){b=document.createElement('div');b.id='offlineBanner';b.textContent='Немає з’єднання з сервером — дані можуть бути застарілими';document.body.append(b)}else if(!on&&b)b.remove()}
function legacyCopy(text){try{const ta=document.createElement('textarea');ta.value=text;ta.setAttribute('readonly','');ta.style.cssText='position:fixed;top:-1000px;opacity:0';document.body.appendChild(ta);ta.select();ta.setSelectionRange(0,ta.value.length);const done=document.execCommand('copy');ta.remove();return done}catch{return false}}
// navigator.clipboard exists only in a secure context (HTTPS/localhost). The studio is
// usually opened over plain HTTP on the LAN, so fall back to the legacy copy path.
function copyText(btn){const t=btn?.dataset?.copy||'';if(!t)return;const ok=()=>toast('Скопійовано'),bad=()=>toast('Не вдалося скопіювати',true);if(navigator.clipboard&&window.isSecureContext){navigator.clipboard.writeText(t).then(ok).catch(()=>{legacyCopy(t)?ok():bad()})}else{legacyCopy(t)?ok():bad()}}
function hint(text){return `<span class="hint" tabindex="0" role="img" aria-label="${esc(text)}" data-tip="${esc(text)}">i</span>`}
function bootScreen(){root.innerHTML=`<div class="boot-screen"><img src="${LOGO}" alt="ARTLINE"><div class="boot-spinner"></div><p>Завантаження робочого простору…</p></div>`}
let keysBound=false;
function bindKeys(){if(keysBound)return;keysBound=true;document.addEventListener('keydown',e=>{if(e.key==='/'&&!e.target.matches('input,textarea,select')){const s=document.querySelector('input[placeholder^="Пошук"]');if(s){e.preventDefault();s.focus()}}})}
async function boot(){bindKeys();if(!state.token)return render();bootScreen();try{await loadAll()}catch(x){toast(x.message,true)}render();startLive()}
async function loadAll(){const core=await Promise.all([api('/api/me'),api('/api/projects'),api('/api/styles'),api('/api/models'),api('/api/assets')]);[state.me,state.projects,state.styles,state.models,state.assets]=core;if(can('usage.view'))state.usage=await api('/api/usage').catch(()=>({}));if(can('users.manage'))state.users=await api('/api/users').catch(()=>[]);await loadSecrets();if(state.selected)await refreshSelected()}
async function loadUsage(){if(can('usage.view'))state.usage=await api('/api/usage').catch(()=>state.usage)}
async function refreshSelected(){const [p,e]=await Promise.all([api(`/api/projects/${state.selected.id}`),api(`/api/projects/${state.selected.id}/events`)]);state.selected=p;state.events=e;selectArtifact(state.artifact?.id,false)}
let live,liveSig='',liveFails=0;
function liveSignature(){return JSON.stringify({page:state.page,tab:state.tab,projects:state.projects.map(x=>[x.id,x.status,x.stage,x.progress,x.estimated_cost,x.name,x.sku,x.product_category]),sel:state.selected?[state.selected.id,state.selected.status,state.selected.stage,state.selected.progress,state.selected.estimated_cost,(state.selected.artifacts||[]).length,(state.selected.critics||[]).length,state.events[0]?.id]:null,assets:state.page==='media'?state.assets.length:0})}
function startLive(){clearInterval(live);liveSig=liveSignature();live=setInterval(async()=>{if(!state.token)return;try{state.projects=await api('/api/projects');if(state.selected)await refreshSelected();else if(state.page==='media')state.assets=await api('/api/assets');liveFails=0;setOffline(false);const sig=liveSignature();if(sig===liveSig)return;const active=document.activeElement;const userIsInteracting=document.querySelector('dialog[open]')||active?.matches('input,textarea,select,iframe')||(state.selected&&['preview','html'].includes(state.tab));if(userIsInteracting)return;liveSig=sig;const y=scrollY;render();scrollTo(0,y)}catch{liveFails++;if(liveFails>=2)setOffline(true)}},2500)}
async function login(e){e.preventDefault();const f=new FormData(e.target);try{const d=await api('/api/auth/login',{method:'POST',body:JSON.stringify({email:f.get('email'),password:f.get('password')})});state.token=d.access_token;localStorage.setItem('token',state.token);await boot()}catch(x){toast(x.message,true)}}
function logout(){localStorage.removeItem('token');location.reload()}
function loginView(){root.innerHTML=`<div class="auth"><form onsubmit="login(event)"><img class="auth-logo" src="${LOGO}" alt="ARTLINE"><h1>Вхід до робочого простору</h1><p>Генерація та керування rich-контентом.</p><label>Email<input name="email" type="email" required></label><label>Пароль<input name="password" type="password" required></label><button class="btn primary">Увійти</button></form></div>`}
// Access is driven by effective permissions (role defaults + per-user overrides),
// resolved by the API and returned in state.me.permissions. The UI mirrors them.
const can=p=>(state.me?.permissions||[]).includes(p);
const allowedPages=()=>['projects',...(can('style.manage')?['styles']:[]),...(can('media.view')?['media']:[]),...(can('usage.view')?['usage']:[]),...(can('users.manage')?['users']:[]),...(can('settings.view')?['settings']:[])];
function allowedTabs(){const t=['overview','preview'];if(can('project.edit_html'))t.push('html');if(can('media.view'))t.push('assets');if(can('review.request_changes')||can('review.approve'))t.push('review');t.push('activity');return t}
function shell(content){const pages=allowedPages(),nav=[['projects','Проєкти'],['styles','Стилі'],['media','Медіа'],['usage','Використання'],['users','Користувачі'],['settings','Налаштування']].filter(x=>pages.includes(x[0]));root.innerHTML=`<div class="shell"><aside><div class="brand-lockup"><img src="${LOGO}" alt="ARTLINE"><small>Rich Studio</small></div><nav>${nav.map(([k,v])=>`<button class="${state.page===k?'active':''}" onclick="go('${k}')">${v}</button>`).join('')}</nav><div class="userbox"><b>${esc(state.me?.name||state.me?.email)}</b><small>${ROLE_LABEL[state.me?.role]||esc(state.me?.role)}</small><button onclick="logout()">Вийти</button></div></aside><main><div class="appbar"><span>Платформа AI rich-контенту</span><span class="api-state">${state.models.source==='openai+configuration'?'Моделі OpenAI синхронізовано':'Моделі з конфігурації'}</span></div><div class="container">${content}</div></main></div>`}
function go(page){state.page=page;state.selected=null;state.styleEdit=null;if(page==='settings')loadSystem().then(render);if(page==='usage')loadUsage().then(render);render()}
const projectCategories=()=>[...new Set(state.projects.map(x=>(x.product_category||'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'uk'));
function filtered(){let rows=[...state.projects],q=state.search.toLowerCase().trim();if(q)rows=rows.filter(x=>(x.name+' '+x.source_url+' '+x.text_model+' '+(x.sku||'')+' '+(x.product_category||'')).toLowerCase().includes(q));if(state.status!=='all')rows=rows.filter(x=>x.status===state.status);if(state.category!=='all')rows=rows.filter(x=>state.category==='none'?!(x.product_category||'').trim():(x.product_category||'').trim()===state.category);const split=state.sort.lastIndexOf('_'),key=state.sort.slice(0,split),dir=state.sort.slice(split+1);rows.sort((a,b)=>{let av,bv;if(key==='name'){av=(a.name||'').toLowerCase();bv=(b.name||'').toLowerCase()}else if(key==='category'){av=(a.product_category||'￿').toLowerCase();bv=(b.product_category||'￿').toLowerCase();const c=av.localeCompare(bv,'uk');return c*(dir==='asc'?1:-1)||(a.name||'').localeCompare(b.name||'','uk')}else if(key==='cost'){av=a.estimated_cost||0;bv=b.estimated_cost||0}else if(key==='duration'){av=a.duration_seconds||0;bv=b.duration_seconds||0}else{av=new Date(a[key]||0).getTime();bv=new Date(b[key]||0).getTime()}return (av>bv?1:av<bv?-1:0)*(dir==='asc'?1:-1)});return rows}
function badge(s){return `<span class="badge ${s}">${STATUS[s]||s}</span>`}
function progress(p){return `<div class="progress"><i style="width:${p||0}%"></i></div>`}
function setProjectView(view){state.projectView=view;localStorage.setItem('projectView',view);render()}
function projectsPage(){const rows=filtered(),cats=projectCategories(),sortOptions=[['finished_at_desc','Нещодавно завершені'],['created_at_desc','Спочатку нові'],['created_at_asc','Спочатку старі'],['name_asc','За назвою'],['category_asc','За категорією'],['cost_desc','За вартістю'],['duration_desc','За часом']];shell(`<header class="pagehead"><div><small class="eyebrow">КЕРУВАННЯ КОНТЕНТОМ ARTLINE</small><h1>Проєкти</h1><p>Вставте посилання на товар — назва визначиться автоматично.</p></div>${can('project.create')?`<button class="btn primary" onclick="newProject.showModal()">+ Новий проєкт</button>`:''}</header><section class="toolbar project-toolbar"><input placeholder="Пошук за назвою, артикулом, URL або моделлю" value="${esc(state.search)}" oninput="state.search=this.value;render()"><select onchange="state.status=this.value;render()"><option value="all">Усі статуси</option>${Object.entries(STATUS).map(([k,v])=>`<option value="${k}" ${state.status===k?'selected':''}>${v}</option>`).join('')}</select><select onchange="state.category=this.value;render()"><option value="all">Усі категорії</option>${cats.map(c=>`<option value="${esc(c)}" ${state.category===c?'selected':''}>${esc(c)}</option>`).join('')}<option value="none" ${state.category==='none'?'selected':''}>Без категорії</option></select><select onchange="state.sort=this.value;render()">${sortOptions.map(([value,label])=>`<option value="${value}" ${state.sort===value?'selected':''}>${label}</option>`).join('')}</select><div class="view-switch" aria-label="Вигляд проєктів"><button class="${state.projectView==='cards'?'active':''}" onclick="setProjectView('cards')">Картки</button><button class="${state.projectView==='list'?'active':''}" onclick="setProjectView('list')">Список</button></div></section><section class="project-grid ${state.projectView==='list'?'list-view':''}">${rows.map(p=>`<article class="project" role="button" tabindex="0" onclick="openProject('${p.id}')" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();openProject('${p.id}')}" ><div class="project-top">${badge(p.status)}<small title="${dt(p.created_at)}">${rel(p.created_at)}</small></div><h3>${esc(p.name)}</h3><p>${esc(p.source_url)}</p>${p.sku?`<p class="project-sku">Артикул: <b>${esc(p.sku)}</b></p>`:''}<div class="stage-row"><span>${STAGE[p.stage]||'Опрацювання'}</span><b>${p.progress||0}%</b></div>${progress(p.progress)}<div class="project-style">${p.product_category?`<span class="cat-chip">${esc(p.product_category)}</span>`:''}Стиль: <b>${esc(p.style_name||'Не визначено')}</b></div><div class="project-meta"><span>${esc(p.text_model)}</span><span>${money(p.estimated_cost)}</span><span>${Number(p.duration_seconds||0).toFixed(0)} сек</span></div></article>`).join('')||emptyProjects()}</section>${projectDialog()}`)}
function emptyProjects(){const hasFilters=state.search||state.status!=='all'||state.category!=='all';if(hasFilters&&state.projects.length)return `<div class="empty"><b>Нічого не знайдено</b><p>Змініть пошук або фільтри — проєкти є, але вони приховані поточними умовами.</p><button class="btn secondary" onclick="state.search='';state.status='all';state.category='all';render()">Скинути фільтри</button></div>`;return `<div class="empty"><b>Проєктів поки немає</b><p>Вставте посилання на сторінку товару — система збере факти й характеристики, підготує зображення та згенерує rich-контент кількома мовами.</p>${['admin','editor'].includes(state.me?.role)?`<button class="btn primary" onclick="newProject.showModal()">+ Створити перший проєкт</button>`:''}</div>`}
function options(items,selected){return items.map(x=>`<option value="${esc(x)}" ${x===selected?'selected':''}>${esc(x)}</option>`).join('')}
function dataList(id,items){return `<datalist id="${id}">${items.map(x=>`<option value="${esc(x)}"></option>`).join('')}</datalist>`}
const QUICK_LANGS=['ua','ru','pl'];
function languagePicker(selected=['ua','ru']){const chosen=new Set(selected||[]),custom=[...chosen].filter(x=>!QUICK_LANGS.includes(x)),extra=[...LANGUAGE_OPTIONS.filter(x=>!QUICK_LANGS.includes(x)),'bg','lt','lv','et','uk'];return `<fieldset class="language-fieldset"><legend>Мови результату</legend><div class="language-grid">${QUICK_LANGS.map(code=>`<label class="check"><input type="checkbox" name="language" value="${code}" ${chosen.has(code)?'checked':''}> ${LANG[code]}</label>`).join('')}</div><label class="custom-language">Додати інші мови <em>почніть вводити код: en, de, fr, es, bg, en-GB…</em><input name="custom_languages" value="${esc(custom.join(', '))}" placeholder="en, de, fr, es, it, cs…" list="extraLangs"></label>${dataList('extraLangs',extra)}</fieldset>`}
function collectLanguages(form){const values=[...form.querySelectorAll('[name=language]:checked')].map(x=>x.value),custom=String(new FormData(form).get('custom_languages')||'').split(/[\s,;]+/).map(x=>x.trim()).filter(Boolean);return [...new Set([...values,...custom])]}
function projectDialog(){return `<dialog id="newProject"><form onsubmit="createProject(event)"><div class="dialog-head"><div><small class="eyebrow">НОВИЙ ПРОЄКТ</small><h2>Створити rich-контент</h2></div><button type="button" onclick="newProject.close()">×</button></div><label>Посилання на товар<input name="source_url" type="url" placeholder="https://artline.ua/..." required></label><div class="form-grid"><label>Стиль<select name="style_id">${state.styles.map(s=>`<option value="${s.id}" ${s.is_default?'selected':''}>${esc(s.name)}</option>`).join('')}</select></label><label><span class="lbl">Текстова модель ${hint('Модель для аналізу товару, генерації та перекладу тексту. Впливає на якість тексту й вартість токенів.')}</span><select name="text_model">${options([...new Set([state.models.default_text_model,...(state.models.text_models||[])].filter(Boolean))],state.models.default_text_model)}</select></label><label><span class="lbl">Модель зображень ${hint('Модель для генерації Hero/Feature зображень із реального фото товару. Разом із «Якість» визначає вартість зображень.')}</span><input name="image_model" list="imageModels" value="${esc(state.models.default_image_model||'')}" placeholder="Оберіть або введіть model ID">${dataList('imageModels',state.models.image_models||[])}</label><label><span class="lbl">Якість ${hint('Деталізація й роздільність AI-зображень Hero та Feature і їх вартість. gpt-image-1: low ≈ $0.02, medium ≈ $0.07, high ≈ $0.19 за зображення. Діє лише коли стиль генерує зображення (є Hero/Feature промпти й знайдено фото товару).')}</span><select name="image_quality"><option>low</option><option selected>medium</option><option>high</option></select></label></div><div class="form-grid"><label>Власне Hero URL <em>необов’язково</em><input name="custom_hero_url" type="url" placeholder="https://..."></label><label>Власне Feature URL <em>необов’язково</em><input name="custom_feature_url" type="url" placeholder="https://..."></label></div>${languagePicker(['ua','ru'])}<fieldset><legend>Формати</legend><div class="language-grid"><label class="check"><input type="checkbox" name="variant" value="desktop" checked> Десктоп</label><label class="check"><input type="checkbox" name="variant" value="mobile" checked> Мобільна</label></div></fieldset><button class="btn primary">Створити й запустити</button></form></dialog>`}
async function createProject(e){e.preventDefault();const form=e.currentTarget,f=new FormData(form),payload={source_url:f.get('source_url'),style_id:f.get('style_id')||null,text_model:f.get('text_model'),image_model:f.get('image_model'),image_quality:f.get('image_quality'),custom_hero_url:f.get('custom_hero_url')||'',custom_feature_url:f.get('custom_feature_url')||'',languages:collectLanguages(form),variants:[...form.querySelectorAll('[name=variant]:checked')].map(x=>x.value)};try{const p=await api('/api/projects',{method:'POST',body:JSON.stringify(payload)});newProject.close();toast('Проєкт додано до черги');await loadAll();await openProject(p.id)}catch(x){toast(x.message,true)}}
async function openProject(id){state.artifact=null;state.selected=await api(`/api/projects/${id}`);state.events=await api(`/api/projects/${id}/events`);state.tab='overview';selectArtifact(null,false);render()}
function selectArtifact(id,rerender=true){const list=state.selected?.artifacts||[],latest=[...list].sort((a,b)=>(b.version-a.version)||(new Date(b.created_at)-new Date(a.created_at)))[0]||null;state.artifact=(id&&list.find(x=>x.id===id))||state.artifact&&list.find(x=>x.id===state.artifact.id)||latest;if(rerender)render()}
function workspace(){const p=state.selected,limit=allowedTabs(),tabs=[['overview','Огляд'],['preview','Перегляд'],['html','HTML'],['assets','Медіа'],['review','Перевірка'],['activity','Історія']].filter(t=>!limit||limit.includes(t[0]));if(limit&&!limit.includes(state.tab))state.tab=limit[0];const liveState=['processing','queued'].includes(p.status)?'run':p.status==='error'?'bad':['paused','cancelled','changes_requested'].includes(p.status)?'warn':'ok';shell(`<header class="project-head"><div><button class="link" onclick="state.selected=null;render()">← Усі проєкти</button><h1>${esc(p.name)}</h1><a class="source-link" href="${esc(p.source_url)}" target="_blank" rel="noopener noreferrer" title="Відкрити сторінку товару">${esc(p.source_url)} ↗</a></div><div>${projectActions(p)}</div></header><section class="live-card ${liveState}"><div class="live-title"><div><span class="pulse"></span><b>${STAGE[p.stage]||'Опрацювання проєкту'}</b></div><strong>${p.progress||0}%</strong></div>${progress(p.progress)}<small>${STATUS[p.status]||p.status}</small></section>${p.status==='error'&&p.error?`<section class="error-island"><b>Помилка генерації</b><p>${esc(p.error)}</p>${['admin','editor'].includes(state.me?.role)?`<button class="btn secondary" onclick="queueAction('resume',this)">Спробувати ще раз</button>`:''}</section>`:''}<section class="metrics project-metrics"><div><small>Стиль</small><b>${esc(p.style_name||'Не визначено')}</b></div><div><small>Текстова модель</small><b>${esc(p.text_model)}</b></div><div><small>Зображення</small><b>${esc(p.image_model)}</b></div><div><small>Вартість</small><b>${money(p.estimated_cost)}</b></div><div><small>Час</small><b id="liveTimer">${Number(p.duration_seconds||0).toFixed(0)} с</b></div><div><small>Токени</small><b>${(p.input_tokens||0)+(p.output_tokens||0)}</b></div></section><div class="tabs">${tabs.map(([k,v])=>`<button class="${state.tab===k?'active':''}" onclick="state.tab='${k}';render()">${v}</button>`).join('')}</div>${projectTab()}${rerunProjectDialog()}`);startProjectTimer()}
let projTimer;
function tickTimer(){const el=document.getElementById('liveTimer'),p=state.selected;if(!el||!p){clearInterval(projTimer);return}if(!['processing','queued'].includes(p.status)){el.textContent=`${Number(p.duration_seconds||0).toFixed(0)} с`;clearInterval(projTimer);return}const start=p.started_at?new Date(String(p.started_at).endsWith('Z')?p.started_at:p.started_at+'Z').getTime():Date.now();const sec=Math.max(0,(Date.now()-start)/1000);const m=Math.floor(sec/60),s=Math.floor(sec%60);el.textContent=m?`${m} хв ${s} с`:`${s} с`}
function startProjectTimer(){clearInterval(projTimer);tickTimer();const p=state.selected;if(p&&['processing','queued'].includes(p.status))projTimer=setInterval(tickTimer,1000)}
function projectTab(){if(state.tab==='preview')return preview();if(state.tab==='html')return htmlEditor();if(state.tab==='assets')return projectAssets();if(state.tab==='review')return reviewTab();if(state.tab==='activity')return activity();const p=state.selected;return `<section class="panel"><div class="sku-strip"><div><small>Артикул (SKU)</small><b>${p.sku?esc(p.sku):'—'}</b></div>${p.sku?`<button class="btn ghost" data-copy="${esc(p.sku)}" onclick="copyText(this)">Копіювати</button>`:''}</div><div class="summary-grid"><div><small>Категорія</small><h3>${esc(p.product_category||'Визначається')}</h3></div><div><small>Мови</small><h3>${p.languages.map(languageLabel).join(', ')}</h3></div><div><small>Формати</small><h3>${p.variants.map(x=>VARIANT[x]).join(', ')}</h3></div></div><h2>Останні етапи</h2><div class="timeline">${state.events.slice(0,8).map(e=>`<div><time>${dt(e.created_at)}</time><b>${STAGE[e.stage]||'Опрацювання'}</b><span>${esc(e.message)}</span></div>`).join('')||'<p>Подій поки немає.</p>'}</div></section>${costPanel(p)}`}
function costPanel(p){const b=p.cost_breakdown||{},rows=[['extract','Аналіз товару'],['content','Генерація тексту'],['images','Зображення']],has=rows.some(([k])=>b[k]);return `<section class="panel cost-panel"><h2>Вартість за етапами</h2>${has?`<table class="cost-table"><thead><tr><th>Етап</th><th>Обсяг</th><th>Вартість</th></tr></thead><tbody>${rows.map(([k,label])=>{const s=b[k]||{},detail=k==='images'?`${s.count||0} зобр.`:`${(s.input_tokens||0)+(s.output_tokens||0)} ток.`;return `<tr><td>${label}</td><td>${detail}</td><td>${money(s.cost)}</td></tr>`}).join('')}<tr class="cost-total"><td>Разом</td><td></td><td>${money(b.total||p.estimated_cost)}</td></tr></tbody></table>`:`<p class="muted-note">Деталізація з’явиться під час генерації. Поточна оцінка: <b>${money(p.estimated_cost)}</b>.</p>`}</section>`}
function artifactSelect(){return `<select onchange="selectArtifact(this.value)">${(state.selected.artifacts||[]).map(a=>`<option value="${a.id}" ${state.artifact?.id===a.id?'selected':''}>${languageLabel(a.language)} · ${VARIANT[a.variant]} · v${a.version}</option>`).join('')}</select>`}
function previewDocument(html){return `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><base href="${location.origin}/"><style>html,body{margin:0;min-height:100%;background:#fff;color:#101010}body{padding:0;font-family:Roboto,Inter,Arial,sans-serif}</style></head><body>${html}</body></html>`}
function openPreview(){if(!state.artifact?.html)return toast('Немає результату для перегляду',true);const win=window.open('about:blank','_blank');if(!win)return toast('Браузер заблокував нову вкладку',true);win.document.open();win.document.write(previewDocument(state.artifact.html));win.document.close()}
function preview(){if(!state.artifact)return'<div class="empty">Результат ще не створено.</div>';const variant=state.artifact.variant==='mobile'?'mobile':'desktop';return `<section class="panel preview-panel"><div class="panel-tools">${artifactSelect()}<div class="preview-hint">${variant==='mobile'?'Мобільне полотно · 480 px':'Десктопне полотно · 1240 px'}</div><button class="btn secondary" onclick="openPreview()">Відкрити окремо</button></div><div class="preview-stage"><div class="preview-canvas ${variant}"><iframe title="Попередній перегляд rich-контенту" sandbox="allow-same-origin" scrolling="yes" srcdoc="${esc(previewDocument(state.artifact.html))}"></iframe></div></div></section>`}
function htmlEditor(){if(!state.artifact)return'<div class="empty">HTML ще не створено.</div>';return `<section class="panel"><div class="panel-tools">${artifactSelect()}<button class="btn primary" onclick="saveHtml(this)">Зберегти нову версію</button></div><textarea id="htmlEditor" class="code">${esc(state.artifact.html)}</textarea></section>`}
function projectAssets(){const a=state.selected.assets||[];return `<section class="media-grid">${a.map(asset=>mediaCard(asset)).join('')||'<div class="empty">Зображень поки немає.</div>'}</section><dialog id="assetDetails"></dialog>`}
function mediaCard(a){const label=assetLabel(a);return `<article class="media-card"><div class="media-image"><img src="${esc(a.url)}" alt="${esc(label)}" loading="lazy"></div><div><span class="badge neutral">${esc(label)}</span><h3>${a.width&&a.height?`${a.width} × ${a.height}`:'Зображення'}</h3>${a.project_name?`<p class="media-project" title="${esc(a.project_name)}">${esc(a.project_name)}</p>`:''}<p>${esc(a.model==='source'?'Вихідне фото':a.model||'Джерело')}</p><small>${money(a.cost)} · ${dt(a.created_at)}</small><div class="media-actions"><button class="btn secondary" onclick="showAsset('${a.id}')">Докладніше</button><a class="btn ghost" href="${esc(a.url)}" download>Завантажити</a></div></div></article>`}
function showAsset(id){const a=state.assets.find(x=>x.id===id)||(state.selected?.assets||[]).find(x=>x.id===id);if(!a)return toast('Медіафайл не знайдено',true);const label=assetLabel(a),source=a.metadata?.source_url||a.metadata?.reference_url||'';let dlg=document.getElementById('assetDetails');if(!dlg){dlg=document.createElement('dialog');dlg.id='assetDetails';document.body.appendChild(dlg)}dlg.innerHTML=`<form method="dialog"><div class="dialog-head"><div><small class="eyebrow">МЕДІАФАЙЛ</small><h2>${esc(label)}</h2></div><button aria-label="Закрити">×</button></div><div class="asset-detail-image"><img src="${esc(a.url)}" alt="${esc(label)}"></div><div class="summary-grid"><div><small>Модель</small><h3>${esc(a.model==='source'?'Вихідне фото':a.model||'Джерело')}</h3></div><div><small>Розмір</small><h3>${a.width&&a.height?`${a.width} × ${a.height}`:'—'}</h3></div><div><small>Вартість</small><h3>${money(a.cost)}</h3></div></div>${source?`<label>Вихідний референс<input value="${esc(source)}" readonly></label>`:''}<label>Промпт<textarea rows="8" readonly>${esc(a.prompt||'Для вихідного фото промпт не використовується')}</textarea></label><div class="row"><a class="btn primary" href="${esc(a.url)}" target="_blank" rel="noopener">Відкрити оригінал</a><a class="btn secondary" href="${esc(a.url)}" download>Завантажити</a></div></form>`;dlg.showModal()}
function criticsPanel(){const critics=state.selected?.critics||[];return `<section class="panel"><div class="panel-tools"><h2>AI-перевірка якості</h2>${can('review.request_changes')||can('project.create')?`<button class="btn secondary" onclick="rerunCritic(this)">Перезапустити перевірку</button>`:''}</div><p class="critic-note">Це автоматичні евристичні перевірки: структура HTML, наявність назви й фактів товару, alt-тексти й доступність, надмірність маркетингу. Вони швидко підсвічують ризики, але <b>не гарантують якість і не замінюють ручну перевірку</b> — сприймайте оцінки як підказку, а не остаточний вердикт.</p>${critics.length?`<div class="metrics">${critics.map(c=>`<div><small>${CRITIC_LABEL[c.type]||esc(c.type)}</small><b>${Math.round(c.score)}</b></div>`).join('')}</div>${critics.filter(c=>(c.issues||[]).length).map(c=>`<div class="critic-block"><b>${CRITIC_LABEL[c.type]||esc(c.type)}</b><div class="issue-list">${c.issues.map(i=>`<div>${esc(i)}</div>`).join('')}</div></div>`).join('')||'<p class="critic-clean">Критичних зауважень не знайдено.</p>'}`:'<div class="empty">Перевірку ще не виконано.</div>'}</section>`}
const DECISION_LABEL={approve:'Схвалено',request_changes:'Запитано зміни',submit:'Надіслано на перевірку'};
function reviewChecklist(){const p=state.selected||{};return [['facts','Факти та цифри'],['images','Зображення'],['html','HTML і верстка'],...(p.languages||[]).map(l=>[`lang_${l}`,`Мова: ${languageLabel(l)}`]),...(p.variants||[]).map(v=>[`variant_${v}`,`Формат: ${VARIANT[v]||v}`])]}
function reviewHistory(){const rows=state.selected?.reviews||[];if(!rows.length)return '';return `<section class="panel"><h2>Історія перевірок</h2><div class="review-log">${rows.map(r=>{const checked=Object.entries(r.checklist||{}).filter(([,v])=>v).map(([k])=>k);return `<div class="review-entry ${r.decision}"><div class="review-entry-head"><b>${DECISION_LABEL[r.decision]||esc(r.decision)}</b><span>${esc(r.reviewer||'—')} · ${dt(r.created_at)}</span></div>${r.comment?`<p>${esc(r.comment)}</p>`:''}<small>Перевірено пунктів: ${checked.length} з ${Object.keys(r.checklist||{}).length||'—'}</small></div>`}).join('')}</div></section>`}
function reviewTab(){const canChanges=can('review.request_changes'),canApprove=can('review.approve'),canDecide=canChanges||canApprove;return `${criticsPanel()}<section class="panel"><h2>Контроль якості</h2><p class="critic-note">Пройдіться по пунктах нижче, звіряючи їх із вкладкою «Перегляд». Список формується з мов і форматів саме цього проєкту. Позначені пункти зберігаються разом із рішенням і залишаються в історії перевірок.</p><div class="review-grid">${reviewChecklist().map(([x,label])=>`<label class="check"><input type="checkbox" name="reviewcheck" value="${x}"> ${label}</label>`).join('')}</div><label>Коментар <em>обов’язковий, якщо запитуєте зміни</em><textarea id="reviewComment" rows="5" placeholder="Що саме потрібно виправити або що перевірено"></textarea></label>${canDecide?`<div class="panel-tools review-actions">${canChanges?`<button class="btn danger" onclick="review('request_changes',this)">Запросити зміни</button>`:''}${canApprove?`<button class="btn primary" onclick="review('approve',this)">Схвалити</button>`:''}</div>`:'<p class="muted-note">У вас немає прав на рішення щодо перевірки.</p>'}</section>${reviewHistory()}`}
function projectActions(p){const busy=['processing','queued'].includes(p.status),stopped=['paused','cancelled','error'].includes(p.status),canQueue=can('project.create'),btns=[];if(busy&&canQueue){btns.push(`<button class="btn secondary" onclick="queueAction('pause',this)">Пауза</button>`);btns.push(`<button class="btn danger" onclick="queueAction('cancel',this)">Скасувати</button>`)}if(stopped&&canQueue)btns.push(`<button class="btn secondary" onclick="queueAction('resume',this)">Відновити</button>`);btns.push(`<button class="btn secondary" onclick="downloadArchive()">Завантажити ZIP</button>`);if(canQueue)btns.push(`<button class="btn secondary" onclick="document.getElementById('rerunProjectDialog').showModal()">Повторити генерацію</button>`);if(can('project.delete')&&!busy)btns.push(`<button class="btn danger" onclick="deleteProject(this)">Видалити</button>`);return btns.join('')}
async function queueAction(action,button){const original=button?.textContent;if(button){button.disabled=true;button.textContent='…'}try{await api(`/api/projects/${state.selected.id}/queue`,{method:'POST',body:JSON.stringify({action})});toast(action==='pause'?'Проєкт призупинено':action==='cancel'?'Проєкт скасовано':'Проєкт повернуто в чергу');await refreshSelected();state.projects=await api('/api/projects');render()}catch(x){toast(x.message,true);if(button){button.disabled=false;button.textContent=original}}}
async function deleteProject(button){if(!confirm('Видалити проєкт разом з усіма версіями, зображеннями та історією? Дію не можна скасувати.'))return;if(button)button.disabled=true;try{await api(`/api/projects/${state.selected.id}`,{method:'DELETE'});toast('Проєкт видалено');state.selected=null;state.projects=await api('/api/projects');render()}catch(x){toast(x.message,true);if(button)button.disabled=false}}
async function rerunCritic(button){const original=button?.textContent;if(button){button.disabled=true;button.textContent='Перевірка…'}try{await api(`/api/projects/${state.selected.id}/critic`,{method:'POST',body:JSON.stringify({auto_fix:false})});await refreshSelected();toast('Перевірку якості оновлено');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
function activity(){return `<section class="panel"><h2>Історія проекта</h2><div class="timeline">${state.events.map(e=>`<div><time>${dt(e.created_at)}</time><b>${STAGE[e.stage]||'Опрацювання'}</b><span>${esc(e.message)}</span></div>`).join('')}</div></section>`}
function rerunProjectDialog(){const p=state.selected||{},current=p.style_id,variants=p.variants||['desktop','mobile'];return `<dialog id="rerunProjectDialog"><form onsubmit="rerun(event)"><div class="dialog-head"><div><small class="eyebrow">ПОВТОРНА ГЕНЕРАЦІЯ</small><h2>Налаштуйте новий запуск</h2></div><button type="button" onclick="document.getElementById('rerunProjectDialog').close()">×</button></div><label>Стиль для нової генерації<select name="style_id" required>${state.styles.map(s=>`<option value="${s.id}" ${s.id===current?'selected':''}>${esc(s.name)}${s.is_default?' · базовий':''}</option>`).join('')}</select></label>${languagePicker(p.languages||['ua','ru'])}<fieldset><legend>Формати</legend><div class="language-grid"><label class="check"><input type="checkbox" name="variant" value="desktop" ${variants.includes('desktop')?'checked':''}> Десктоп</label><label class="check"><input type="checkbox" name="variant" value="mobile" ${variants.includes('mobile')?'checked':''}> Мобільна</label></div></fieldset>${reuseImagesField()}<p class="dialog-note">Попередні HTML-версії залишаться в історії. Текст буде створено заново за обраним стилем, мовами й форматами.</p><button class="btn primary">Запустити повторно</button></form></dialog>`}
function reuseImagesField(){const imgs=(state.selected?.assets||[]).filter(a=>a.kind==='image'&&/^(hero|feature)/.test(a.label||''));if(!imgs.length)return '';const cost=imgs.filter(a=>Number(a.cost)>0).reduce((s,a)=>s+Number(a.cost||0),0);return `<fieldset class="language-fieldset"><legend>Зображення</legend><label class="check"><input type="checkbox" name="reuse_images" checked> Використати наявні зображення (${imgs.length} шт.)</label><p class="muted-note" style="margin-top:8px">Зніміть галочку, щоб створити зображення заново${cost?` — це додасть близько ${money(cost)} до вартості`:''}. З галочкою перегенерується лише текст: швидше й без витрат на зображення.</p></fieldset>`}
async function rerun(e){e.preventDefault();const form=e.currentTarget,button=e.submitter,original=button?.textContent;if(button){button.disabled=true;button.textContent='Запуск…'}try{const data=new FormData(form),payload={style_id:data.get('style_id'),languages:collectLanguages(form),variants:[...form.querySelectorAll('[name=variant]:checked')].map(x=>x.value),reuse_images:!!form.querySelector('[name=reuse_images]:checked')};await api(`/api/projects/${state.selected.id}/run`,{method:'POST',body:JSON.stringify(payload)});form.closest('dialog').close();toast('Генерацію запущено з новими параметрами');await refreshSelected();state.projects=await api('/api/projects');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
async function downloadArchive(){if(!state.selected)return;try{toast('Підготовка ZIP-архіву…');const response=await fetch(`/api/projects/${state.selected.id}/archive`,{headers:{Authorization:`Bearer ${state.token}`}});if(!response.ok){const text=await response.text();let detail=text;try{detail=JSON.parse(text)?.detail||text}catch{}throw Error(detail||`HTTP ${response.status}`)}const blob=await response.blob(),disposition=response.headers.get('content-disposition')||'',match=disposition.match(/filename="([^"]+)"/),filename=match?.[1]||'artline-rich.zip',url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=filename;document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(url),3000);toast('Архів завантажено')}catch(x){toast(x.message,true)}}
async function saveHtml(button){if(pendingSave)return;pendingSave=true;const original=button?.textContent;if(button){button.disabled=true;button.textContent='Збереження…'}try{const editor=document.getElementById('htmlEditor');const d=await api(`/api/artifacts/${state.artifact.id}`,{method:'PUT',body:JSON.stringify({html:editor.value})});await refreshSelected();state.artifact=(state.selected.artifacts||[]).find(x=>x.id===d.id)||d;toast(`Збережено версію v${d.version}`);render()}catch(x){toast(x.message,true)}finally{pendingSave=false;if(button){button.disabled=false;button.textContent=original}}}
async function review(decision,button){if(pendingSave)return;pendingSave=true;const original=button?.textContent;if(button){button.disabled=true;button.textContent='Збереження…'}try{const checks=Object.fromEntries([...document.querySelectorAll('[name=reviewcheck]')].map(x=>[x.value,x.checked]));const comment=document.getElementById('reviewComment')?.value||'';const d=await api(`/api/projects/${state.selected.id}/review`,{method:'POST',body:JSON.stringify({decision,comment,checklist:checks})});toast(d.message||'Рішення збережено');await refreshSelected();render()}catch(x){toast(x.message,true)}finally{pendingSave=false;if(button){button.disabled=false;button.textContent=original}}}
function stylesPage(){const s=state.styleEdit||state.styles[0]||{};shell(`<header class="pagehead"><div><small class="eyebrow">РУШІЙ СТИЛІВ</small><h1>Стилі</h1><p>Створюйте, покращуйте та версіонуйте дизайн-код rich-контенту.</p></div><div><button class="btn secondary" onclick="styleGenerator.showModal()">Згенерувати стиль</button><button class="btn primary" onclick="state.styleEdit={};state.styleTab='general';render()">+ Новий стиль</button></div></header><section class="style-shell"><div class="style-list">${state.styles.map(x=>`<button class="${s.id===x.id?'active':''}" onclick="state.styleEdit=state.styles.find(y=>y.id==='${x.id}');render()"><b>${esc(x.name)}</b><small>${[x.is_default?'За замовчуванням':'',MANAGED_STYLE_NAMES.includes(x.name)?'Керований':'Власний'].filter(Boolean).join(' · ')}</small></button>`).join('')}</div><div><div class="subtabs">${[['general','Основне'],['html','HTML'],['images','Зображення'],['quality','Якість'],['preview','Перегляд']].map(([k,v])=>`<button class="${state.styleTab===k?'active':''}" onclick="state.styleTab='${k}';render()">${v}</button>`).join('')}</div>${styleEditor(s)}</div></section>${styleGeneratorDialog()}`)}
function styleEditor(s){const score=s.score||{};if(state.styleTab==='preview'){if(s.id&&state.stylePreviewFor!==s.id){state.stylePreviewFor=s.id;state.stylePreview=null;state.stylePreviewSource='';loadStylePreview(s.id)}const noteMap={demo:'Швидка демонстрація макета без AI — однакова для всіх стилів. Натисніть «Згенерувати AI-приклад», щоб побачити сторінку саме за цим стилем.',saved:'Збережений приклад цього стилю.',generated:'AI-приклад, згенерований за цим стилем на демо-товарі.'};return `<section class="panel"><div class="panel-tools"><h2>Демонстрація стилю</h2>${s.id&&can('style.manage')?`<button class="btn primary" onclick="generateStylePreview('${s.id}',this)">Згенерувати AI-приклад</button>`:''}</div>${state.stylePreview?`<div class="preview-stage style-demo"><div class="preview-canvas desktop"><iframe title="Демонстрація стилю" sandbox="allow-same-origin" scrolling="yes" srcdoc="${esc(previewDocument(state.stylePreview))}"></iframe></div></div><p class="muted-note">${noteMap[state.stylePreviewSource]||''}</p>`:s.id?'<div class="empty">Завантаження демонстрації…</div>':'<div class="empty">Спершу збережіть стиль.</div>'}</section>`}if(state.styleTab==='quality')return `<section class="panel"><div class="panel-tools"><h2>Якість стилю</h2><div class="row"><button class="btn secondary" onclick="analyzeStyle()">Перевірити стиль</button>${s.id?`<button class="btn ghost" onclick="loadStyleVersions('${s.id}')">Історія версій</button>`:''}</div></div><div class="metrics"><div><small>Узгодженість</small><b>${score.consistency||'—'}</b></div><div><small>Читабельність</small><b>${score.readability||'—'}</b></div><div><small>Відповідність ARTLINE</small><b>${score.brand_fit||'—'}</b></div></div>${state.styleIssues.length?`<div class="issue-list">${state.styleIssues.map(x=>`<div>${esc(x)}</div>`).join('')}</div>`:''}${state.styleVersions.length?`<div class="version-list">${state.styleVersions.map(v=>`<button onclick="restoreStyleVersion(${v.version})"><b>v${v.version}</b><small>${dt(v.created_at)}</small></button>`).join('')}</div>`:''}${s.id?`<label>Що покращити<textarea id="improveInstructions" rows="5" placeholder="Наприклад: зробити Hero преміальнішим і зменшити візуальний шум"></textarea></label><button class="btn primary" onclick="improveStyle('${s.id}')">Покращити стиль через AI</button>`:''}</section>`;return `<form class="panel style-form" onsubmit="saveStyle(event)" oninput="scheduleStyleAutosave(event)" onchange="scheduleStyleAutosave(event)"><input type="hidden" name="id" value="${esc(s.id||'')}">${state.styleTab==='general'?`<label>Назва<input name="name" value="${esc(s.name||'')}" required></label><label>Опис<textarea name="description" rows="5">${esc(s.description||'')}</textarea></label><label class="check"><input type="checkbox" name="is_default" ${s.is_default?'checked':''}> Використовувати за замовчуванням</label>`:''}${state.styleTab==='html'?`<label>Єдиний Style Prompt<textarea name="prompt" rows="24">${esc(s.prompt||'')}</textarea></label>`:''}${state.styleTab==='images'?`<label>Промпт Hero <em>необов’язково</em><textarea name="hero_prompt" rows="10">${esc(s.hero_prompt||'')}</textarea></label><label>Промпт Feature <em>необов’язково</em><textarea name="feature_prompt" rows="10">${esc(s.feature_prompt||'')}</textarea></label><label>Негативний промпт<textarea name="negative_prompt" rows="7">${esc(s.negative_prompt||'')}</textarea></label>`:''}<div class="style-savebar"><span id="styleSaveStatus">${s.id?'Усі зміни зберігаються автоматично':'Заповніть поля та створіть стиль'}</span><div class="row">${s.id?styleDeleteButton(s):`<button class="btn primary">Створити стиль</button>`}</div></div></form>`}
// Always render the delete control, disabled with the reason — a button that simply
// vanishes leaves people hunting for it.
function styleDeleteButton(s){if(!can('style.manage'))return '';let why='';if(MANAGED_STYLE_NAMES.includes(s.name))why='Керований стиль — його відновлює система під час запуску';else if(s.is_default)why='Спершу призначте інший стиль за замовчуванням';return why?`<button type="button" class="btn danger" disabled title="${esc(why)}">Видалити стиль</button><span class="delete-why">${esc(why)}</span>`:`<button type="button" class="btn danger" onclick="deleteStyle('${s.id}')">Видалити стиль</button>`}
async function loadStylePreview(id){try{const d=await api(`/api/styles/${id}/preview`);if(state.stylePreviewFor!==id)return;state.stylePreview=d.html;state.stylePreviewSource=d.source;render()}catch(x){toast(x.message,true)}}
async function generateStylePreview(id,button){const original=button?.textContent;if(button){button.disabled=true;button.textContent='Генерація…'}try{const d=await api(`/api/styles/${id}/preview`,{method:'POST'});state.stylePreviewFor=id;state.stylePreview=d.html;state.stylePreviewSource=d.source;state.styles=await api('/api/styles');if(state.styleEdit?.id===id)state.styleEdit=state.styles.find(x=>x.id===id)||state.styleEdit;toast(d.source==='generated'?'AI-приклад згенеровано та збережено':'AI недоступний — показано демо-шаблон',d.source!=='generated');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
async function deleteStyle(id){if(!confirm('Видалити стиль? Проєкти, що його використовують, буде переприв’язано до базового стилю.'))return;try{const d=await api(`/api/styles/${id}`,{method:'DELETE'});state.styles=await api('/api/styles');state.styleEdit=state.styles.find(x=>x.is_default)||state.styles[0]||null;toast(d.reassigned_projects?`Стиль видалено, проєктів переприв’язано: ${d.reassigned_projects}`:'Стиль видалено');render()}catch(x){toast(x.message,true)}}
function collectStyleForm(f){const base=state.styleEdit||state.styles[0]||{};return {name:f.get('name')||base.name||'Новий стиль',description:f.get('description')??base.description??'',prompt:f.get('prompt')??base.prompt??'',hero_prompt:f.get('hero_prompt')??base.hero_prompt??'',feature_prompt:f.get('feature_prompt')??base.feature_prompt??'',negative_prompt:f.get('negative_prompt')??base.negative_prompt??'',score:base.score||{},preview_html:base.preview_html||'',is_default:state.styleTab==='general'?f.get('is_default')==='on':!!base.is_default}}
function styleSaveMessage(text,bad=false){const node=document.getElementById('styleSaveStatus');if(node){node.textContent=text;node.classList.toggle('bad',bad)}}
function scheduleStyleAutosave(e){const form=e.currentTarget,id=new FormData(form).get('id'),payload=collectStyleForm(new FormData(form));state.styleEdit={...(state.styleEdit||{}),...payload};if(!id)return;styleSaveRevision+=1;stylePendingSave={id,payload,revision:styleSaveRevision};clearTimeout(styleSaveTimer);styleSaveMessage('Є незбережені зміни…');styleSaveTimer=setTimeout(flushStyleAutosave,850)}
async function flushStyleAutosave(){if(styleSaveBusy||!stylePendingSave)return;const item=stylePendingSave;stylePendingSave=null;styleSaveBusy=true;styleSaveMessage('Збереження…');try{const saved=await api(`/api/styles/${item.id}`,{method:'PUT',body:JSON.stringify(item.payload)});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);if(item.revision===styleSaveRevision)state.styleEdit=saved;styleSaveMessage('Збережено автоматично')}catch(x){styleSaveMessage('Помилка збереження',true);toast(x.message,true)}finally{styleSaveBusy=false;if(stylePendingSave){clearTimeout(styleSaveTimer);styleSaveTimer=setTimeout(flushStyleAutosave,300)}}}
async function saveStyle(e){e.preventDefault();if(pendingSave)return;pendingSave=true;const button=e.submitter;const original=button?.textContent;if(button){button.disabled=true;button.textContent='Збереження…'}const f=new FormData(e.target),id=f.get('id'),payload=collectStyleForm(f);try{const d=await api(id?`/api/styles/${id}`:'/api/styles',{method:id?'PUT':'POST',body:JSON.stringify(payload)});state.styles=await api('/api/styles');state.styleEdit=state.styles.find(x=>x.id===(d.id||id))||state.styles[0];toast('Стиль збережено');render()}catch(x){toast(x.message,true)}finally{pendingSave=false;if(button){button.disabled=false;button.textContent=original}}}
function styleGeneratorDialog(){return `<dialog id="styleGenerator"><form onsubmit="generateStyle(event)"><div class="dialog-head"><div><small class="eyebrow">AI-ГЕНЕРАТОР СТИЛІВ</small><h2>Створити дизайн-стиль</h2></div><button type="button" onclick="styleGenerator.close()">×</button></div><label>Назва<input name="name" value="ARTLINE Premium" required></label><label>Опис бажаного результату<textarea name="brief" rows="8" placeholder="Категорія товару, настрій, структура блоків, рівень преміальності, обмеження..."></textarea></label><div class="form-grid"><label>Категорія<input name="category" placeholder="3D-принтери, енергетика, ігрові ПК..."></label><label>Настрій<input name="mood" placeholder="Преміальний, технічний, мінімалістичний..."></label></div><label>URL-референс <em>необов’язково</em><input name="reference_url" type="url"></label><label>Модель<input name="model" list="styleModels" value="${esc(state.models.default_text_model||'')}">${dataList('styleModels',state.models.text_models||[])}</label><button class="btn primary">Згенерувати</button></form></dialog>`}
async function generateStyle(e){e.preventDefault();const f=new FormData(e.target),button=e.submitter,original=button?.textContent;if(button){button.disabled=true;button.textContent='Генерація…'}try{const request=Object.fromEntries(f);request.brief=[request.brief,request.category&&`Category: ${request.category}`,request.mood&&`Mood: ${request.mood}`].filter(Boolean).join('\n');const d=await api('/api/styles/generate',{method:'POST',body:JSON.stringify(request)}),payload={name:f.get('name'),description:d.description||'',prompt:d.style_prompt||'',hero_prompt:d.hero_prompt||'',feature_prompt:d.feature_prompt||'',negative_prompt:d.negative_prompt||'',score:d.score||{},preview_html:d.preview_html||'',is_default:false},saved=await api('/api/styles',{method:'POST',body:JSON.stringify(payload)});state.styles=await api('/api/styles');state.styleEdit=state.styles.find(x=>x.id===saved.id)||saved;styleGenerator.close();state.styleTab='preview';toast('Стиль згенеровано та збережено');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
async function analyzeStyle(){const s=state.styleEdit||{};try{const d=await api('/api/styles/analyze',{method:'POST',body:JSON.stringify({prompt:s.prompt||'',hero_prompt:s.hero_prompt||'',feature_prompt:s.feature_prompt||'',negative_prompt:s.negative_prompt||''})}),updated={...s,score:d.score};state.styleEdit=updated;state.styleIssues=d.issues||[];if(s.id){const saved=await api(`/api/styles/${s.id}`,{method:'PUT',body:JSON.stringify({name:updated.name,description:updated.description||'',prompt:updated.prompt||'',hero_prompt:updated.hero_prompt||'',feature_prompt:updated.feature_prompt||'',negative_prompt:updated.negative_prompt||'',score:updated.score||{},preview_html:updated.preview_html||'',is_default:!!updated.is_default})});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);state.styleEdit=saved}toast(d.ready?'Стиль перевірено та збережено':'Рекомендації збережено',!d.ready);render()}catch(x){toast(x.message,true)}}
async function loadStyleVersions(id){try{state.styleVersions=await api(`/api/styles/${id}/versions`);render()}catch(x){toast(x.message,true)}}
async function restoreStyleVersion(version){const v=state.styleVersions.find(x=>x.version===version),s=state.styleEdit;if(!v||!s?.id)return;try{const payload={name:s.name,description:s.description||'',prompt:v.prompt||'',hero_prompt:v.hero_prompt||'',feature_prompt:v.feature_prompt||'',negative_prompt:s.negative_prompt||'',score:s.score||{},preview_html:s.preview_html||'',is_default:!!s.is_default},saved=await api(`/api/styles/${s.id}`,{method:'PUT',body:JSON.stringify(payload)});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);state.styleEdit=saved;state.styleTab='html';toast(`Версію v${version} відновлено та збережено`);render()}catch(x){toast(x.message,true)}}
async function improveStyle(id){try{const d=await api(`/api/styles/${id}/improve`,{method:'POST',body:JSON.stringify({instructions:improveInstructions.value,model:state.models.default_text_model})}),s=state.styleEdit,payload={name:s.name,description:d.description||s.description||'',prompt:d.style_prompt||s.prompt||'',hero_prompt:d.hero_prompt||s.hero_prompt||'',feature_prompt:d.feature_prompt||s.feature_prompt||'',negative_prompt:d.negative_prompt||s.negative_prompt||'',score:d.score||s.score||{},preview_html:d.preview_html||s.preview_html||'',is_default:!!s.is_default},saved=await api(`/api/styles/${id}`,{method:'PUT',body:JSON.stringify(payload)});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);state.styleEdit=saved;state.styleTab='preview';toast('Покращену версію збережено');render()}catch(x){toast(x.message,true)}}
function mediaPage(){const filters=[['all','Усі джерела'],['generated','Згенеровані AI'],['source','Вихідні фото товару'],['custom','Власні фото']],roles=[['all','Усі ролі'],['hero','Hero'],['feature','Feature'],['reference','Референси'],['other','Інші']],sorts=[['created_desc','Спочатку нові'],['created_asc','Спочатку старі'],['size_desc','Найбільша роздільність'],['cost_desc','Найвища вартість'],['project_asc','За назвою проєкту'],['role_asc','За типом зображення']],projects=[...new Map(state.assets.filter(x=>x.project_id).map(x=>[x.project_id,x.project_name||x.project_id])).entries()].sort((a,b)=>String(a[1]).localeCompare(String(b[1]),'uk'));let rows=[...state.assets];if(state.mediaFilter!=='all')rows=rows.filter(x=>assetCategory(x)===state.mediaFilter);if(state.mediaRole!=='all')rows=rows.filter(x=>assetRole(x)===state.mediaRole);if(state.mediaProject!=='all')rows=rows.filter(x=>x.project_id===state.mediaProject);const q=state.mediaSearch.trim().toLowerCase();if(q)rows=rows.filter(x=>[x.project_name,assetLabel(x),x.model,x.prompt].some(v=>String(v||'').toLowerCase().includes(q)));rows.sort((a,b)=>{if(state.mediaSort==='created_asc')return new Date(a.created_at)-new Date(b.created_at);if(state.mediaSort==='size_desc')return Number(b.width||0)*Number(b.height||0)-Number(a.width||0)*Number(a.height||0);if(state.mediaSort==='cost_desc')return Number(b.cost||0)-Number(a.cost||0);if(state.mediaSort==='project_asc')return String(a.project_name||'').localeCompare(String(b.project_name||''),'uk');if(state.mediaSort==='role_asc')return assetRole(a).localeCompare(assetRole(b))||new Date(b.created_at)-new Date(a.created_at);return new Date(b.created_at)-new Date(a.created_at)});shell(`<header class="pagehead"><div><small class="eyebrow">МЕДІАТЕКА</small><h1>Медіа</h1><p>Знаходьте зображення за проєктом, призначенням, джерелом і параметрами.</p></div></header><section class="toolbar media-toolbar advanced"><input placeholder="Пошук за проєктом, моделлю або промптом" value="${esc(state.mediaSearch)}" oninput="state.mediaSearch=this.value;render()"><select onchange="state.mediaFilter=this.value;render()">${filters.map(([value,label])=>`<option value="${value}" ${state.mediaFilter===value?'selected':''}>${label}</option>`).join('')}</select><select onchange="state.mediaRole=this.value;render()">${roles.map(([value,label])=>`<option value="${value}" ${state.mediaRole===value?'selected':''}>${label}</option>`).join('')}</select><select onchange="state.mediaProject=this.value;render()"><option value="all">Усі проєкти</option>${projects.map(([id,name])=>`<option value="${esc(id)}" ${state.mediaProject===id?'selected':''}>${esc(name)}</option>`).join('')}</select><select onchange="state.mediaSort=this.value;render()">${sorts.map(([value,label])=>`<option value="${value}" ${state.mediaSort===value?'selected':''}>${label}</option>`).join('')}</select><b>${rows.length} файлів</b></section><section class="media-grid">${rows.map(mediaCard).join('')||'<div class="empty">За обраними фільтрами зображень немає.</div>'}</section><dialog id="assetDetails"></dialog>`) }
function usagePage(){const q=state.usage.quality||{};const rate=v=>v==null?'—':`${v}%`;shell(`<header class="pagehead"><div><small class="eyebrow">ВИКОРИСТАННЯ</small><h1>Використання</h1><p>Час, токени, вартість і довіра до результату.</p></div></header><section class="metrics large"><div><small>Загальна вартість</small><b>${money(state.usage.total_cost)}</b></div><div><small>Проєкти</small><b>${state.usage.projects||0}</b></div><div><small>Вхідні токени</small><b>${state.usage.input_tokens||0}</b></div><div><small>Вихідні токени</small><b>${state.usage.output_tokens||0}</b></div><div><small>Зображення</small><b>${state.usage.images||0}</b></div></section><section class="panel quality-panel"><h2>Якість результату</h2><p class="critic-note">Головний показник корисності інструмента: скільки перевірених сторінок команда схвалює і як часто доводиться правити HTML руками. Якщо частка схвалень падає нижче ~70% — генерація потребує уваги.</p><div class="metrics"><div><small>Схвалено з перевірених</small><b class="${(q.approve_rate??100)<70?'quality-bad':''}">${rate(q.approve_rate)}</b></div><div><small>Схвалено без запиту змін</small><b>${rate(q.clean_approve_rate)}</b></div><div><small>Перевірено проєктів</small><b>${q.reviewed_projects||0}</b></div><div><small>Ручних правок HTML</small><b>${q.manual_html_edits||0}</b></div><div><small>Згенеровано сторінок</small><b>${q.generated_pages||0}</b></div></div></section>`)}
function usersPage(){shell(`<header class="pagehead"><div><small class="eyebrow">ДОСТУП</small><h1>Користувачі</h1><p>Створюйте облікові записи безпосередньо або запрошуйте за посиланням.</p></div><div><button class="btn secondary" onclick="inviteDialog.showModal()">Запросити</button><button class="btn primary" onclick="createUserDialog.showModal()">+ Створити користувача</button></div></header><section class="panel table-wrap"><table><thead><tr><th>Користувач</th><th>Роль</th><th>Активний</th><th>Останній вхід</th><th>Дії</th></tr></thead><tbody>${state.users.map(u=>`<tr><td><b>${esc(u.name||u.email)}</b>${u.is_root?'<span class="cat-chip" style="margin-left:6px">Головний</span>':''}<small>${esc(u.email)}</small></td><td>${u.is_root?`<span class="badge approved">${ROLE_LABEL[u.role]}</span>`:`<select onchange="updateUser('${u.id}','role',this.value)">${['admin','editor','reviewer','viewer'].map(r=>`<option value="${r}" ${u.role===r?'selected':''}>${ROLE_LABEL[r]}</option>`).join('')}</select>`}</td><td><input type="checkbox" ${u.active?'checked':''} ${u.is_root?'disabled':''} onchange="updateUser('${u.id}','active',this.checked)"></td><td title="${dt(u.last_login_at)}">${rel(u.last_login_at)}</td><td><div class="row">${u.is_root?'<small class="muted-note">Керується через .env</small>':`<button class="btn ghost" onclick="openPerms('${u.id}')">Доступи</button><button class="btn ghost" onclick="resetPassword('${u.id}')">Пароль</button>${u.id!==state.me.id?`<button class="btn danger" onclick="deleteUser('${u.id}')">Видалити</button>`:''}`}</div></td></tr>`).join('')}</tbody></table></section>${userDialogs()}`)}
function userDialogs(){return `<dialog id="createUserDialog"><form onsubmit="createUser(event)"><div class="dialog-head"><h2>Створити користувача</h2><button type="button" onclick="createUserDialog.close()">×</button></div><label>Ім’я<input name="name" required></label><label>Email<input name="email" type="email" required></label><label>Пароль<input name="password" type="password" minlength="8" required></label><label>Роль<select name="role"><option value="editor">Редактор</option><option value="reviewer">Рев’юер</option><option value="viewer">Перегляд</option><option value="admin">Адміністратор</option></select></label><button class="btn primary">Створити</button></form></dialog><dialog id="inviteDialog"><form onsubmit="inviteUser(event)"><div class="dialog-head"><h2>Запросити користувача</h2><button type="button" onclick="inviteDialog.close()">×</button></div><label>Email<input name="email" type="email" required></label><label>Роль<select name="role"><option value="editor">Редактор</option><option value="reviewer">Рев’юер</option><option value="viewer">Перегляд</option><option value="admin">Адміністратор</option></select></label><button class="btn primary">Створити посилання</button></form></dialog>`}
async function createUser(e){e.preventDefault();try{await api('/api/users',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});createUserDialog.close();state.users=await api('/api/users');toast('Користувача створено');render()}catch(x){toast(x.message,true)}}
async function inviteUser(e){e.preventDefault();try{const d=await api('/api/users/invites',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});inviteDialog.close();prompt('Посилання для реєстрації',location.origin+d.register_path)}catch(x){toast(x.message,true)}}
async function updateUser(id,key,value){await api(`/api/users/${id}`,{method:'PATCH',body:JSON.stringify({[key]:value})});state.users=await api('/api/users');render()}
async function resetPassword(id){const password=prompt('Новий пароль (щонайменше 8 символів)');if(!password)return;try{await api(`/api/users/${id}/password`,{method:'POST',body:JSON.stringify({password})});toast('Пароль оновлено')}catch(x){toast(x.message,true)}}
async function deleteUser(id){if(!confirm('Видалити користувача?'))return;try{await api(`/api/users/${id}`,{method:'DELETE'});state.users=await api('/api/users');toast('Користувача видалено');render()}catch(x){toast(x.message,true)}}
async function openPerms(id){const u=state.users.find(x=>x.id===id);if(!u)return;try{if(!state.permCatalog)state.permCatalog=await api('/api/permissions')}catch(x){return toast(x.message,true)}const cat=state.permCatalog,defaults=new Set(cat.role_defaults[u.role]||[]),eff=new Set(u.permissions||[]);let dlg=document.getElementById('permsDialog');if(!dlg){dlg=document.createElement('dialog');dlg.id='permsDialog';document.body.appendChild(dlg)}dlg.innerHTML=`<form onsubmit="savePerms(event,'${u.id}')"><div class="dialog-head"><div><small class="eyebrow">ДОСТУПИ</small><h2>${esc(u.name||u.email)}</h2></div><button type="button" onclick="permsDialog.close()">×</button></div><p class="muted-note">Роль <b>${ROLE_LABEL[u.role]||u.role}</b> дає базовий набір прав (позначено «за роллю»). Тут можна точково додати або прибрати окремі права саме цьому користувачу.</p><div class="perm-list">${cat.permissions.map(p=>`<label class="check perm-row"><input type="checkbox" name="perm" value="${p.key}" ${eff.has(p.key)?'checked':''}><span><b>${esc(p.label)}</b>${defaults.has(p.key)?'<em class="perm-default">за роллю</em>':''}</span></label>`).join('')}</div><button class="btn primary">Зберегти доступи</button></form>`;dlg.showModal()}
async function savePerms(e,id){e.preventDefault();const u=state.users.find(x=>x.id===id),defaults=new Set(state.permCatalog.role_defaults[u.role]||[]),form=e.currentTarget;const checked=new Set([...form.querySelectorAll('[name=perm]:checked')].map(x=>x.value));const grant=[],revoke=[];state.permCatalog.permissions.forEach(p=>{const on=checked.has(p.key),def=defaults.has(p.key);if(on&&!def)grant.push(p.key);if(!on&&def)revoke.push(p.key)});try{await api(`/api/users/${id}/permissions`,{method:'PATCH',body:JSON.stringify({grant,revoke})});state.users=await api('/api/users');if(id===state.me.id)state.me=await api('/api/me');form.closest('dialog').close();toast('Доступи оновлено');render()}catch(x){toast(x.message,true)}}
const fmtBytes=n=>{if(!n)return '0 Б';const u=['Б','КБ','МБ','ГБ','ТБ'];let i=0;while(n>=1024&&i<u.length-1){n/=1024;i++}return `${n.toFixed(n>=10||i===0?0:1)} ${u[i]}`};
const okBadge=(ok,yes='Працює',no='Недоступно')=>`<span class="badge ${ok?'approved':'error'}">${ok?yes:no}</span>`;
function settingsPage(){const s=state.system;shell(`<header class="pagehead"><div><small class="eyebrow">НАЛАШТУВАННЯ</small><h1>Налаштування</h1><p>Стан системи, конфігурація та доступні моделі. ${state.me?.is_root?'Ключі змінюються тут, решта — у <code>.env</code> на сервері.':'Значення змінюються у файлі <code>.env</code> на сервері.'}</p></div><div><button class="btn secondary" onclick="reloadSystem(this)">Оновити стан</button><button class="btn secondary" onclick="reloadModels()">Оновити моделі</button></div></header>
${s?`<section class="panel"><h2>Стан системи</h2><div class="metrics settings-metrics"><div><small>Версія</small><b>v${esc(s.version)}</b></div><div><small>OpenAI API</small><b>${okBadge(s.openai_configured,'Налаштовано','Немає ключа')}</b></div><div><small>Черга (Redis)</small><b>${okBadge(s.redis_ok)}</b></div><div><small>Worker</small><b>${okBadge(s.worker_ok)}</b></div><div><small>Сторож зависань</small><b>${s.watchdog_minutes} хв</b></div><div><small>Сповіщення</small><b>${s.alerts_telegram||s.alerts_webhook?[s.alerts_telegram?'Telegram':'',s.alerts_webhook?'Webhook':''].filter(Boolean).join(' + '):'<span class="muted-note">вимкнено</span>'}</b></div></div>${!s.openai_configured?'<p class="critic-note">Без ключа OpenAI генерація працює в офлайн-режимі на вбудованому шаблоні.</p>':''}${!s.worker_ok?'<p class="critic-note">Worker не відповідає — нові проєкти застрягнуть у черзі. Перевірте <code>docker compose ps</code> на сервері.</p>':''}</section>
<section class="two"><div class="panel"><h2>Дані</h2><div class="metrics"><div><small>Проєкти</small><b>${s.projects}</b></div><div><small>Стилі</small><b>${s.styles}</b></div><div><small>Користувачі</small><b>${s.users}</b></div></div><div class="metrics"><div><small>Медіафайли</small><b>${s.media_files} · ${fmtBytes(s.media_bytes)}</b></div><div><small>Вільно на диску</small><b class="${s.disk_free_bytes&&s.disk_free_bytes<5*1024**3?'quality-bad':''}">${fmtBytes(s.disk_free_bytes)}</b></div><div><small>Схема БД</small><b>${esc(s.db_schema)}</b></div></div></div><div class="panel"><h2>Моделі за замовчуванням</h2><div class="metrics"><div><small>Текст</small><b>${esc(s.default_text_model)}</b></div><div><small>Зображення</small><b>${esc(s.default_image_model)}</b></div><div><small>Reasoning effort</small><b>${esc(s.reasoning_effort||'—')}</b></div></div><p class="muted-note">Модель для конкретного проєкту можна змінити в діалозі створення.</p></div></section>`:'<section class="panel"><div class="empty">Завантаження стану системи…</div></section>'}
<section class="two"><div class="panel"><h2>Текстові моделі</h2><p>Джерело: <b>${esc(state.models.source)}</b></p><div class="model-list">${state.models.text_models.map(x=>`<code>${esc(x)}</code>`).join('')}</div></div><div class="panel"><h2>Моделі зображень</h2><div class="model-list">${state.models.image_models.map(x=>`<code>${esc(x)}</code>`).join('')}</div><h2>Моделі міркування</h2><div class="model-list">${(state.models.reasoning_models||[]).map(x=>`<code>${esc(x)}</code>`).join('')||'<small>Окремих reasoning-моделей немає.</small>'}</div></div></section>
${secretsPanel()}
<section class="panel"><h2>Довідка</h2><p class="muted-note">Посібник редактора — <code>USER_GUIDE.md</code>, деплой і бекапи — <code>DEPLOY.md</code> у репозиторії. Бекап БД створюється автоматично щодня контейнером <code>backup</code>.</p></section>`)}
function secretsPanel(){if(!state.me?.is_root)return '';const k=state.secrets;if(!k)return `<section class="panel"><h2>Ключі та провайдер</h2><div class="empty">Завантаження…</div></section>`;const src=v=>v==='database'?'<span class="key-src db">збережено в БД</span>':v==='env'?'<span class="key-src env">з .env</span>':'<span class="key-src none">не задано</span>';const or=k.llm_provider==='openrouter';return `<section class="panel"><div class="panel-tools"><h2>Ключі та провайдер ${hint('Доступно лише головному адміністратору. Ключ зберігається в базі й перекриває значення з .env. API і worker підхоплюють новий ключ протягом ~15 секунд без перезапуску.')}</h2><div class="row"><button class="btn secondary" onclick="testSecrets(this)">Перевірити зв’язок</button></div></div><form class="secrets-form" onsubmit="saveSecrets(event)"><label>Провайдер тексту<select name="llm_provider" onchange="state.secrets.llm_provider=this.value;render()">${[['openai','OpenAI'],['openrouter','OpenRouter']].map(([v,l])=>`<option value="${v}" ${k.llm_provider===v?'selected':''}>${l}</option>`).join('')}</select></label><label>OpenAI API key ${src(k.openai_api_key_source)}<input name="openai_api_key" autocomplete="off" spellcheck="false" placeholder="${k.openai_api_key?esc(k.openai_api_key):'sk-…'}"></label>${or?`<label>OpenRouter API key ${src(k.openrouter_api_key_source)}<input name="openrouter_api_key" autocomplete="off" spellcheck="false" placeholder="${k.openrouter_api_key?esc(k.openrouter_api_key):'sk-or-v1-…'}"></label><label>Модель OpenRouter<input name="openrouter_text_model" value="${esc(k.openrouter_text_model||'')}" spellcheck="false" placeholder="openai/gpt-4o-mini"></label>`:''}<p class="muted-note">Поле порожнє — ключ не змінюється. Щоб прибрати збережений ключ і повернутись до <code>.env</code>, введіть <code>-</code>.</p>${or?'<p class="critic-note">OpenRouter обслуговує лише текст: генерація зображень завжди йде через OpenAI, бо Images Edit з <code>input_fidelity</code> в OpenRouter немає. Ключ OpenAI має лишатись заповненим.</p>':''}<div class="row"><button class="btn primary">Зберегти ключі</button></div></form></section>`}
async function loadSecrets(){if(!state.me?.is_root)return;try{state.secrets=await api('/api/secrets')}catch{state.secrets=null}}
async function saveSecrets(e){e.preventDefault();const f=new FormData(e.target),body={llm_provider:f.get('llm_provider')};for(const key of ['openai_api_key','openrouter_api_key','openrouter_text_model']){if(!f.has(key))continue;const v=(f.get(key)||'').trim();if(key==='openrouter_text_model'){body[key]=v;continue}if(!v)continue;body[key]=v==='-'?'':v}try{state.secrets=await api('/api/secrets',{method:'PUT',body:JSON.stringify(body)});e.target.reset();toast('Ключі збережено');await loadSystem();render()}catch(x){toast(x.message,true)}}
async function testSecrets(btn){btn.disabled=true;try{const r=await api('/api/secrets/test',{method:'POST'});toast(r.ok?`${r.provider}: зв’язок є, моделей ${r.models}`:`${r.provider}: ${r.detail}`,!r.ok)}catch(x){toast(x.message,true)}finally{btn.disabled=false}}
async function loadSystem(){try{state.system=await api('/api/system')}catch{state.system=null}}
async function reloadSystem(btn){if(btn){btn.disabled=true}try{await loadSystem();await loadSecrets();toast('Стан оновлено');render()}catch(x){toast(x.message,true)}finally{if(btn)btn.disabled=false}}
async function reloadModels(){try{state.models=await api('/api/models');toast('Список моделей оновлено');render()}catch(x){toast(x.message,true)}}
function render(){if(!state.token)return loginView();if(state.selected)return workspace();if(!allowedPages().includes(state.page))state.page=allowedPages()[0]||'projects';({projects:projectsPage,styles:stylesPage,media:mediaPage,usage:usagePage,users:usersPage,settings:settingsPage}[state.page]||projectsPage)()}
boot().catch(e=>{console.error(e);toast(e.message,true);render()});
